import React from "react"
import moment from "moment";
import { properties } from '../../properties/properties.js'
import Select from 'react-select'
import { CSVLink } from "react-csv"
var xlsx = require("xlsx");



class Scheduler extends React.Component {

    constructor(props) {
        super(props);
        this.state = {
            results: [], screen: 0, selectedFile: null, amionData: [], rotationName: [], showRotationName: ""
        };
    }

    handleselectedFile = event => {
        //console.log(event.target.files[0])
        this.setState({
          selectedFile: event.target.files[0]
        })
      }


    handleUpload = (e) => {

        this.setState({screen: 1})

        e.preventDefault();
        var results = []
        var forAmionStartDate = ""
        var forAmionEndDate = ""
        var yearInfo = []
        var rotationArr = []

        /*
        var startDate = ""
        var endDate = ""
*/
/*
        var wb = xlsx.readFile(this.state.selectedFile);


        var wsR1 = wb.Sheets[wb.SheetNames[0]];
        var wsR2 = wb.Sheets[wb.SheetNames[1]];
        var wsR3 = wb.Sheets[wb.SheetNames[2]];


        this.findRotation("UC Card", wsR1)
        */
        var reader = new FileReader();
        const scope = this;
        reader.onload = function (e) {

            function findRotation(forWhichRotation, ws, sheetName) {

                var range = xlsx.utils.decode_range(ws['!ref']);

                var yearInfoString = []

                for (let colNum = 0; colNum <= range.e.c; colNum++) {
                    var yearRow = findV(ws[xlsx.utils.encode_cell({r: 0, c: colNum})])
                    if (yearRow.length > 0 && isNaN(yearRow.substring(0,1))) {
                        yearInfoString = yearRow.split(",")
                    }
                }


                yearInfo = yearInfoString[1].trim().split("-").map(item=>item.trim())
                //console.log(yearInfo)

                var lastDate = ""



                for (let colNum = 0; colNum <= range.e.c; colNum++) {

                    var rotationRow = findV(ws[xlsx.utils.encode_cell({r: 2, c: colNum})])


                    if (rotationRow.length > 0 && !isNaN(rotationRow.substring(0,1))) {

                        var splitDate = rotationRow.split(" ")

                        var yearString = yearInfo[0]

                        var startDate = moment(splitDate[1] + "/" + yearString, "M/D/YYYY").format("YYYY-MM-DD")
                        var endDate = moment(splitDate[3] + "/" + yearString, "M/D/YYYY").format("YYYY-MM-DD")

                        if (lastDate.length > 0 && startDate < lastDate) {
                            startDate = moment(splitDate[1] + "/" + yearInfo[1], "M/D/YYYY").format("YYYY-MM-DD")
                        }
                        if (lastDate.length > 0 && endDate < lastDate) {
                            endDate = moment(splitDate[3] + "/" + yearInfo[1], "M/D/YYYY").format("YYYY-MM-DD")
                        }

                        if (forAmionStartDate === "" || startDate < forAmionStartDate) {
                            forAmionStartDate = startDate
                        }

                        if (forAmionEndDate === "" || endDate > forAmionEndDate) {
                            forAmionEndDate = endDate
                        }


                        lastDate = endDate

                       //console.log("*******************************************************************")
                       //console.log(rotationRow)
                       for (let rowNum = 3; rowNum <= range.e.r; rowNum++) {
                           /*
                            var splitDate = rotationRow.split(" ")
                           if (startDate == "") {
                               startDate = splitDate[1] + "/" + moment().format("YYYY")
                               console.log(startDate)
                           }
                           endDate = splitDate[3] + "/" + moment().format("YYYY")
                           console.log(endDate)
                           */

                           var isRotation = findV(ws[xlsx.utils.encode_cell({r: rowNum, c: colNum})])
                           var data = findV(ws[xlsx.utils.encode_cell({r: rowNum, c: 0})])
                           //if (isRotation === forWhichRotation && data != "OB") {

                            if (isRotation.includes(forWhichRotation)) {
                               var before = ""
                               if (colNum > 1) {
                                   before = findV(ws[xlsx.utils.encode_cell({r: rowNum, c: colNum - 1})])
                               }
                               var after = ""
                               var checkClinics = findV(ws[xlsx.utils.encode_cell({r: 2, c: colNum + 1})])
                               if (checkClinics != "Clinics") {
                                   after = findV(ws[xlsx.utils.encode_cell({r: rowNum, c: colNum + 1})])
                               }
                               var clinic = findV(ws[xlsx.utils.encode_cell({r: rowNum, c: range.e.c})])
                               var lastColumn = findV(ws[xlsx.utils.encode_cell({r: 2, c: range.e.c})])
                               if (lastColumn === "Clinics") {
                                   clinic = ""
                               }
                               //console.log("Name:" + data + " ** before:" + before + " ** rotation:" + forWhichRotation + " ** after:" + after + " ** clinic:" + clinic)

                               results.push({"startDate": startDate, "endDate": endDate, "name": data, "before": before, "after": after, "rotation": isRotation, "clinic": clinic, "sheetName": sheetName, "date": rotationRow })
                           }
                       }
                    }

                }
            }




            function findV(cellValue) {
                var value_v = "";
                if (typeof cellValue !== 'undefined')
                    value_v = cellValue.v
                else
                    value_v = ""
                return value_v;
            }

            function findW(cellValue) {
                var value_w = "";
                if (typeof cellValue !== 'undefined') {
                    value_w = moment(cellValue.w,'M/D/YY').format('MM/DD/YYYY')

                } else {
                    value_w = ""
                }
                return value_w;
            }



            function findRotationV2(ws, sheetName) {

                var range = xlsx.utils.decode_range(ws['!ref']);



                var yearInfoString = []

                for (let colNum = 0; colNum <= range.e.c; colNum++) {
                    var yearRow = findV(ws[xlsx.utils.encode_cell({r: 0, c: colNum})])
                    if (yearRow.length > 0 && isNaN(yearRow.substring(0,1))) {
                        yearInfoString = yearRow.split(",")
                    }
                }


                yearInfo = yearInfoString[1].trim().split("-").map(item=>item.trim())



                var lastDate = ""


                var colClinicNum = 0
                var col1stNum = 0
                var col2ndNum = 0
                var col3rdNum = 0

                for (let colNum = 0; colNum <= range.e.c; colNum++) {

                    var colName = findV(ws[xlsx.utils.encode_cell({r: 2, c: colNum})])

                    if (colName === "clinic") {
                        colClinicNum = colNum
                    }
                    if (colName === "1st pref all day") {
                        col1stNum = colNum
                    }
                    if (colName === "2nd pref all day") {
                        col2ndNum = colNum
                    }
                    if (colName === "3rd pref all day") {
                        col3rdNum = colNum
                    }
                }





                for (let colNum = 0; colNum <= range.e.c; colNum++) {

                    var rotationRow = findV(ws[xlsx.utils.encode_cell({r: 2, c: colNum})])


                    if (rotationRow.includes("-") && rotationRow.length > 0 && !isNaN(rotationRow.substring(0,1))) {

                       // console.log(rotationRow)

                        var splitDate = rotationRow.split(" ")

                        //console.log(splitDate)

                        var yearString = yearInfo[0]


                        //console.log(yearString)

                        var startDate = moment(splitDate[1] + "/" + yearString, "M/D/YYYY").format("YYYY-MM-DD")
                        var endDate = moment(splitDate[3] + "/" + yearString, "M/D/YYYY").format("YYYY-MM-DD")

                        if (lastDate.length > 0 && startDate < lastDate) {
                            startDate = moment(splitDate[1] + "/" + yearInfo[1], "M/D/YYYY").format("YYYY-MM-DD")
                        }
                        if (lastDate.length > 0 && endDate < lastDate) {
                            endDate = moment(splitDate[3] + "/" + yearInfo[1], "M/D/YYYY").format("YYYY-MM-DD")
                        }

                        if (forAmionStartDate === "" || startDate < forAmionStartDate) {
                            forAmionStartDate = startDate
                        }

                        if (forAmionEndDate === "" || endDate > forAmionEndDate) {
                            forAmionEndDate = endDate
                        }


                        lastDate = endDate


                       //console.log("*******************************************************************")
                       //console.log(rotationRow)
                       for (let rowNum = 3; rowNum <= range.e.r; rowNum++) {
                           /*
                            var splitDate = rotationRow.split(" ")
                           if (startDate == "") {
                               startDate = splitDate[1] + "/" + moment().format("YYYY")
                               console.log(startDate)
                           }
                           endDate = splitDate[3] + "/" + moment().format("YYYY")
                           console.log(endDate)
                           */

                           var isRotation = findV(ws[xlsx.utils.encode_cell({r: rowNum, c: colNum})])
                           var data = findV(ws[xlsx.utils.encode_cell({r: rowNum, c: 0})])
                           //if (isRotation === forWhichRotation && data != "OB") {


                            rotationArr.push(isRotation)


                            //if (isRotation.includes(forWhichRotation)) {
                               var before = ""
                               if (colNum > 1) {
                                   before = findV(ws[xlsx.utils.encode_cell({r: rowNum, c: colNum - 1})])
                               }
                               var after = ""
                               var checkClinics = findV(ws[xlsx.utils.encode_cell({r: 2, c: colNum + 1})])
                               if (checkClinics != "Clinics") {
                                   after = findV(ws[xlsx.utils.encode_cell({r: rowNum, c: colNum + 1})])
                               }
                               var clinic = findV(ws[xlsx.utils.encode_cell({r: rowNum, c: range.e.c})])
                               var lastColumn = findV(ws[xlsx.utils.encode_cell({r: 2, c: range.e.c})])
                               if (lastColumn === "Clinics") {
                                   clinic = findV(ws[xlsx.utils.encode_cell({r: rowNum, c: range.e.c})])
                               } else {
                                   clinic = ""
                               }
                               //console.log("Name:" + data + " ** before:" + before + " ** rotation:" + forWhichRotation + " ** after:" + after + " ** clinic:" + clinic)


                                var clinicName = ""
                                var firstPref = ""
                                var secondPref = ""
                                var thirdPref = ""
                                if (colClinicNum != 0) {
                                    clinicName = findV(ws[xlsx.utils.encode_cell({r: rowNum, c: colClinicNum})])
                                }
                                if (col1stNum != 0) {
                                    firstPref = findV(ws[xlsx.utils.encode_cell({r: rowNum, c: col1stNum})])
                                }
                                if (col2ndNum != 0) {
                                    secondPref = findV(ws[xlsx.utils.encode_cell({r: rowNum, c: col2ndNum})])
                                }
                                if (col3rdNum != 0) {
                                    thirdPref = findV(ws[xlsx.utils.encode_cell({r: rowNum, c: col3rdNum})])
                                }



                               results.push({"startDate": startDate, "endDate": endDate, "name": data, "before": before, "after": after, "rotation": isRotation, "clinics": clinic, "sheetName": sheetName, "date": rotationRow, "clinic": clinicName, "firstPref": firstPref, "secondPref": secondPref, "thirdPref": thirdPref })
                           //}
                       }





                    }

                }
            }













            var data = e.target.result;
            let wb = xlsx.read(data, {type: 'binary'});
            //const wsname = readedData.SheetNames[0];
            //const ws = readedData.Sheets[wsname];

            var wsR1 = wb.Sheets[wb.SheetNames[0]];
            var wsR2 = wb.Sheets[wb.SheetNames[1]];
            var wsR3 = wb.Sheets[wb.SheetNames[2]];


            wb.SheetNames.map(sheetnameRec =>
                {
                     //console.log(sheetnameRec)
                     findRotationV2(wb.Sheets[sheetnameRec], sheetnameRec)
                }

            )



/*
            findRotation("UCW", wsR1, wb.SheetNames[0])
            findRotation("UCW", wsR2, wb.SheetNames[1])
            findRotation("UCW", wsR3, wb.SheetNames[2])

            findRotation("UC Card", wsR1, wb.SheetNames[0])
            findRotation("UC Card", wsR2, wb.SheetNames[1])
            findRotation("UC Card", wsR3, wb.SheetNames[2])
            */


            /* Convert array to json*/
            //const dataParse = xlsx.utils.sheet_to_json(ws, {header:1});
            //setFileUploaded(dataParse);

            //console.log(results)
            //return results
            //this.setState({results: results})


            //console.log(forAmionStartDate)
            //console.log(forAmionEndDate)

            var amionData = []

            let headers = new Headers();

            headers.append('Content-Type', 'application/json');
            headers.append('Accept', 'application/json');

            //forAmionStartDate = yearInfo[0] + "-07-01"
            //forAmionEndDate = yearInfo[1] + "-07-01"

            fetch(properties.backend + 'amionmed?startDate=' + forAmionStartDate + '&endDate=' + forAmionEndDate, {
                "method": "GET",
                headers: headers
              })
              .then(response => response.json())
              .then(response => {
                //console.log(response);

                amionData = response.data

                var set = new Set(rotationArr)

                //console.log(rotationArr)
                //console.log(set)

                scope.setState({results: results, amionData: amionData, rotationName: set})

                scope.setState({screen: 2})


            })
            .catch(err => {
              console.log(err);
            });









        };

        reader.readAsBinaryString(this.state.selectedFile)



      }



    componentDidMount() {




      }


      findOnCall = (rec, rec2) => {


        var findAmionData = this.state.amionData.filter(amionRed => amionRed.name == rec2.name && moment(amionRed.date, "M-D-YY" ).format("YYYY-MM-DD") >= moment(rec.startDate, "YYYY-MM-DD").add(-1, "M").format("YYYY-MM-DD") && moment(amionRed.date, "M-D-YY" ).format("YYYY-MM-DD") <= rec.startDate)

        findAmionData.sort(function(a,b) {
            return new Date(b.date) - new Date(a.date)
        })

        var onCallString = ""

        findAmionData.map(aDRec => {
            var before = rec2.before.split("|").map(item=>item.trim())

            before.map(bRec => {
                //console.log(bRec)
                if (bRec.toLowerCase() == "sf5r") {
                    if (aDRec.service.toLowerCase().includes("sf5r int long call") && onCallString == "") {
                        onCallString = moment(aDRec.date, "M-D-YY").format("MM/DD") + " on call"
                    }
                } else {
                    if (aDRec.service.toLowerCase().includes(bRec.toLowerCase()) && aDRec.service.toLowerCase() != bRec.toLowerCase() && onCallString == "") {
                        //console.log(findAmionData)
                        if (!aDRec.service.toLowerCase().includes("sfnfv x-cover")) {
                            onCallString = moment(aDRec.date, "M-D-YY").format("MM/DD") + " on call"
                        }
                    }
                }
            })

        })

        return onCallString

      }

      showRotation = (rotationName) => {

        this.setState({screen: 1})
        this.setState({showRotationName: rotationName})

        this.setState({screen: 2})
        console.log("done on select change")


      }






          render() {


            var header = ""

            var content = []
            //var items = []

            content.push(<div >
            <input type="hidden" name="todayDate" value={this.state.todayDay} />
            <input type="file" name="blockFile" id="blockFile" onChange={this.handleselectedFile} />
            <button onClick={this.handleUpload}>Upload</button>
          </div>)


                if (this.state.screen == 1) {
                    content.push(<div style={{marginTop: "10px"}}>Loading ...</div>)
                }


                if (this.state.screen == 2) {


                    //console.log(this.state.amionData)

                    //console.log(this.state.rotationName)







                const rotationOption = []

                /*
                this.state.rotationName.map(Rec => {
                    rotationOption.push({value: Rec, label: Rec})
                })
                */


                var nameArr = []

                this.state.rotationName.forEach(element => {
                    var splitName = element.split("|")
                    splitName.map(rec => {
                        nameArr.push(rec.trim())
                    })
                })

                var nameSet = new Set(nameArr)

                var nameArrSorted = []

                nameSet.forEach(element => {
                    nameArrSorted.push(element)
                })


                nameArrSorted.sort()


                nameArrSorted.map(element => {
                    rotationOption.push({value: element, label: element})
                })




                  const customStyles = {



                      control: css => ({
                      ...css,
                      width: 400,
                      }),
                      menu: ({ width, ...css }) => ({
                      ...css,
                      width: '400px',
                      minWidth: '20%',
                      }),
                      option: css => ({ ...css, width: 370 }),


                  }



                content.push(<div style={{marginTop: "5px", display: "block"}}><Select
                value={{label: this.state.selectedValue, value: this.state.selectedValue}}
                name="role"
                options={rotationOption}
                className="basic-multi-select"
                classNamePrefix="select"
                 onChange={data => this.showRotation(data.value)}
                width='400px'
                styles={customStyles}
              /></div>)



                var teamChoice = ["A","B","C","D"]
                var teamChoice2 = ["A","B","C","D"]


                var showRotationName = this.state.showRotationName



                  console.log("show rotation ")

                  if (showRotationName.length > 0) {






                  var R1Group = Array.from(new Set(this.state.results.filter(filterRec => filterRec.sheetName == "R1" && filterRec.rotation.includes(showRotationName)).map(groups => groups.date))).map(group => {return {date: group, startDate: this.state.results.filter(Record => Record.date === group && Record.sheetName == "R1" && Record.rotation.includes(showRotationName))[0].startDate, endDate: this.state.results.filter(Record => Record.date === group && Record.sheetName == "R1" && Record.rotation.includes(showRotationName))[0].endDate, data: this.state.results.filter(Record => Record.date === group && Record.sheetName == "R1" && Record.rotation.includes(showRotationName))}});
                  var R2Group = Array.from(new Set(this.state.results.filter(filterRec => (filterRec.sheetName == "R2" || filterRec.sheetName == "R3") && filterRec.rotation.includes(showRotationName)).map(groups => groups.date))).map(group => {return {date: group, startDate: this.state.results.filter(Record => Record.date === group && (Record.sheetName == "R2" || Record.sheetName == "R3")&& Record.rotation.includes(showRotationName))[0].startDate, endDate: this.state.results.filter(Record => Record.date === group && (Record.sheetName == "R2" || Record.sheetName == "R3")&& Record.rotation.includes(showRotationName))[0].endDate, data: this.state.results.filter(Record => Record.date === group && (Record.sheetName == "R2" || Record.sheetName == "R3")&& Record.rotation.includes(showRotationName))}});
                  //var R3GroupUCW = Array.from(new Set(this.state.results.filter(filterRec => filterRec.sheetName == "R3" && filterRec.rotation == "UCW").map(groups => groups.date))).map(group => {return {date: group, data: this.state.results.filter(Record => Record.date === group && Record.sheetName == "R3" && Record.rotation == "UCW")}});



                  console.log("done grouping")

                  //ontent.push(<div><h2>{showRotationName}</h2><hr></hr></div>)



                 // "clinic": clinicName, "firstPref": firstPref, "secondPref": secondPref, "thirdPref": thirdPref




                 var headers = [
                    { label: "", key: "excelDate"},
                    { label: "Team", key: "excelTeam" },
                    { label: "Name", key: "excelName" },
                    { label: "Before", key: "excelBefore"},
                    { label: "Rotation", key: "excelRotation" },
                    { label: "After", key: "excelAfter" },
                    { label: "Clinic", key: "excelClinic" },
                    { label: "First Pref", key: "excelFirstPref" },
                    { label: "Second Pref", key: "excelSecondPref" },
                  ];



                  if (R1Group.length > 0 || R2Group.length > 0) {

                    var excelData = []


                    R1Group.map(rec => {
                        rec.data.map(rec2 => {
                            excelData.push({"excelDate": rec.date, "excelTeam": "", "excelName": rec2.name, "excelBefore": rec2.before + " " + this.findOnCall(rec, rec2), "excelRotation": rec2.rotation, "excelAfter": rec2.after, "excelClinic": rec2.clinic, "excelFirstPref": rec2.firstPref, "excelSecondPref": rec2.secondPref})
                        })
                    })


                    R2Group.map(rec => {
                        rec.data.map(rec2 => {
                            excelData.push({"excelDate": rec.date, "excelTeam": "", "excelName": rec2.name, "excelBefore": rec2.before + " " + this.findOnCall(rec, rec2), "excelRotation": rec2.rotation, "excelAfter": rec2.after, "excelClinic": rec2.clinic, "excelFirstPref": rec2.firstPref, "excelSecondPref": rec2.secondPref})
                        })
                    })

                    var data = excelData;

                    content.push(<div style={{marginTop: "20px", marginBottom: "20px"}}><CSVLink data={data} headers={headers} filename={showRotationName + ".csv"}>
                        Excel Export
                    </CSVLink></div>)

                  }

                  console.log("done excel data")

                  content.push(<div><h2>{showRotationName}</h2></div>)




                  if (R1Group.length > 0) {




                            content.push(<div><h3>Residents</h3><hr></hr></div>)

                            R1Group.map(rec => {
                                content.push(<div><h4>{rec.date}</h4></div>)
                                //content.push(<div><h4>{rec.startDate} - {rec.endDate}</h4></div>)
                                var tr = []


                    if (showRotationName === "UCW") {
                        teamChoice = ["A","B","C","D","E","F","G","H"]
                        teamChoice2 = ["A","B","C","D","E","F","G","H"]
                      } else {
                        teamChoice = ["A","B","C","D"]
                        teamChoice2 = ["A","B","C","D"]
                      }

                                rec.data.map(rec2 => {

                                    var teamString = ""


                                    if (teamChoice.length > 0) {
                                        var arrayRandomNum = Math.floor(Math.random()*teamChoice.length)
                                        teamString = "Team " + teamChoice[arrayRandomNum]
                                        teamChoice.splice(arrayRandomNum, 1)
                                        //console.log(teamChoice)
                                    } else {
                                        if (teamChoice2.length > 0) {
                                            var arrayRandomNum = Math.floor(Math.random()*teamChoice2.length)
                                            teamString = "Team " + teamChoice2[arrayRandomNum]
                                            teamChoice2.splice(arrayRandomNum, 1)
                                            //console.log(teamChoice2)
                                        }
                                    }



                                    tr.push(<tr><td style={{borderWidth: "1px", borderStyle: "solid"}}>{teamString}</td><td style={{borderWidth: "1px", borderStyle: "solid"}}>{rec2.name}</td><td style={{borderWidth: "1px", borderStyle: "solid"}}>{rec2.before + " " + this.findOnCall(rec, rec2)}</td><td style={{borderWidth: "1px", borderStyle: "solid"}}>{rec2.rotation}</td><td style={{borderWidth: "1px", borderStyle: "solid"}}>{rec2.after}</td><td style={{borderWidth: "1px", borderStyle: "solid"}}>{rec2.clinic}</td><td style={{borderWidth: "1px", borderStyle: "solid"}}>{rec2.firstPref}</td><td style={{borderWidth: "1px", borderStyle: "solid"}}>{rec2.secondPref}</td></tr>)
                                })
                                content.push(<div><table style={{borderWidth: "1px", borderStyle: "solid"}}><tr><td></td><td>Name</td><td>Before</td><td>Rotation</td><td>After</td><td>Clinic</td><td>First Pref</td><td>Second Pref</td></tr>{tr}</table></div>)
